    /**
     * Attempts to purchase a product (e.g., In-app purchase via Google Play Billing).
     * @param activity The activity from which the purchase flow will be launched.
     * @param productDetails Details of the product to purchase.
     * @param developerPayload An optional string to be associated with the purchase.
     */
    suspend fun purchaseProduct(activity: Activity, productDetails: ProductDetails, developerPayload: String? = null): TransactionResult

    /**
     * Processes a wallet transaction or an external payment.
     * This method would typically interact with a backend or a third-party payment gateway SDK.
     * @param request The details of the transaction request.
     * @return A TransactionResult indicating success or failure.
     */
    suspend fun processWalletTransaction(request: TransactionRequest): TransactionResult

    /**
     * Queries the user's purchase history.
     * @return A list of PurchaseHistoryItem.
     */
    suspend fun queryPurchaseHistory(): List<PurchaseHistoryItem>

    /**
     * Queries the current wallet balance for the user, if applicable.
     * @return The current WalletBalance or null if not applicable/found.
     */
    suspend fun queryWalletBalance(): WalletBalance?

    /**
     * Consumes an in-app purchase, making it available for purchase again.
     * Applicable mostly to one-time consumable products from Google Play Billing.
     * @param purchaseToken The token of the purchase to consume.
     * @param developerPayload An optional string to be associated with the consumption.
     */
    suspend fun consumePurchase(purchaseToken: String, developerPayload: String? = null): TransactionResult

    /**
     * Observes changes in the user's purchase history or active purchases.
     * Useful for real-time updates after a purchase or refund.
     * @return A Flow of lists of PurchaseHistoryItem.
     */
    fun getPurchaseUpdates(): Flow<List<PurchaseHistoryItem>>

    /**
     * Disconnects the payment processor. Should be called when no longer needed (e.g., app destroyed).
     */
    fun disconnect()
}


