class GooglePlayBillingProcessor(private val applicationContext: Context) : PaymentProcessor, PurchasesUpdatedListener, BillingClientStateListener {

    private var billingClient: BillingClient? = null
    private var isServiceConnected = false
    private var enableDebugLogging = false

