    private val _purchaseUpdates = MutableSharedFlow<List<PurchaseHistoryItem>>(replay = 1)
    override fun getPurchaseUpdates(): SharedFlow<List<PurchaseHistoryItem>> = _purchaseUpdates

    private val scope = CoroutineScope(Dispatchers.IO + SupervisorJob())
    private val billingClientMutex = Mutex() // To ensure only one connection attempt at a time

    override fun initialize(context: Activity, enableDebugLogging: Boolean) {
        this.enableDebugLogging = enableDebugLogging
        if (billingClient == null) {
            billingClient = BillingClient.newBuilder(applicationContext)
                .setListener(this)
                .enablePendingPurchases()
                .build()
        }
        connectToGooglePlayBilling()
    }

    private fun log(message: String) {
        if (enableDebugLogging) {
            println("GooglePlayBillingProcessor: $message")
        }
    }

    private fun connectToGooglePlayBilling() {
        if (!isServiceConnected) {
            scope.launch {
                billingClientMutex.withLock {
                    if (!isServiceConnected) { // Re-check inside lock
                        log("Attempting to connect to Google Play Billing service...")
                        billingClient?.startConnection(this@GooglePlayBillingProcessor)
                    }
                }
            }
        }
    }

    override fun onBillingSetupFinished(billingResult: BillingResult) {
        if (billingResult.responseCode == BillingClient.BillingResponseCode.OK) {
            isServiceConnected = true
            log("Google Play Billing service connected.")
            scope.launch {
                queryAndEmitPurchases()
            }
        } else {
            isServiceConnected = false
            log("Google Play Billing service connection failed: ${billingResult.debugMessage}")
        }
    }

    override fun onBillingServiceDisconnected() {
        isServiceConnected = false
        log("Google Play Billing service disconnected. Reconnecting...")
        // Try to reconnect if service is disconnected
        connectToGooglePlayBilling()
    }

    override fun onPurchasesUpdated(billingResult: BillingResult, purchases: List<Purchase>?) {
        if (billingResult.responseCode == BillingClient.BillingResponseCode.OK && purchases != null) {
            log("Purchases updated: ${purchases.size} new purchases.")
            scope.launch {
                processAndHandlePurchases(purchases)
            }
        } else if (billingResult.responseCode == BillingClient.BillingResponseCode.USER_CANCELED) {
            log("User cancelled the purchase flow.")
            // Emit a cancelled result if a specific purchase was being tracked, or simply log.
        } else {
            log("Purchases update failed: ${billingResult.debugMessage}")
            // Handle other error codes
        }
    }

    private suspend fun queryAndEmitPurchases() {
