                historyItems.add(purchase.toPurchaseHistoryItem(TransactionStatus.SUCCESS))
            } else if (purchase.purchaseState == Purchase.PurchaseState.PENDING) {
                historyItems.add(purchase.toPurchaseHistoryItem(TransactionStatus.PENDING))
            } else {
