            BillingClient.BillingResponseCode.OK -> TransactionResult(productDetails.id, TransactionStatus.PENDING, "Purchase flow launched successfully.")
            BillingClient.BillingResponseCode.USER_CANCELED -> TransactionResult(productDetails.id, TransactionStatus.CANCELLED, "User cancelled purchase.")
            else -> TransactionResult(productDetails.id, TransactionStatus.FAILED, billingResult?.debugMessage ?: "Unknown error.")
        }
    }

    override suspend fun processWalletTransaction(request: TransactionRequest): TransactionResult {
