            log("Failed to consume purchase token $purchaseToken: ${consumeResult?.billingResult?.debugMessage}")
            TransactionResult(purchaseToken, TransactionStatus.FAILED, consumeResult?.billingResult?.debugMessage ?: "Consumption failed.")
        }
    }

    override fun disconnect() {
        log("Disconnecting from Google Play Billing service.")
        billingClient?.endConnection()
        isServiceConnected = false
    }

